#!/usr/bin/env python3
# Piece 1c-soul2 (dream-os) — taper Myra to PURE MANAGER (supersedes 1c-soul).
#
# Carries BOTH soul fixes:
#  1. (from 1c-soul) the one-motion dispatch reflex — route through the operator
#     before replying, never claim done before it's logged.
#  2. (this piece) strip the advisory residue. Myra was asking "which client is
#     this for?" on a reminder about an unknown name (the Kapoors) — that was
#     Harvey-the-advisor's "settle the record-defining gap before you commit"
#     doctrine bleeding into the manager. Manager Myra doesn't interrogate an
#     unknown name; she OPENS A LEAD for it and attaches the work. The new lead
#     appearing in the books IS the flag. Advisory/consult is a separate surface;
#     this one is purely managerial.
#
# Single-file soul edit (myraSoul.js). Lives in Myra's cached block — stable text.

import base64, os, sys
ROOT=os.getcwd()
PAYLOAD = ""
def main():
    p = os.path.join(ROOT,"src","agent","myraSoul.js")
    if not os.path.isfile(p):
        print("ERROR: src/agent/myraSoul.js not found — run from dream-os repo root."); sys.exit(1)
    open(p,"wb").write(base64.b64decode(PAYLOAD))
    print("OK: overwrote src/agent/myraSoul.js")
    print("\nPiece 1c-soul2 written. Myra is pure manager: unknown name -> open a lead, attach, done. No interrogation.")
if __name__=="__main__": main()
